<template><div class="workspace-page"><section class="page-intro"><div><p>只读机构报告</p><h2>{{item?.display_id||'报告详情'}}</h2><span>{{owner?.username ? `${owner.username} · ` : ''}}{{item?.institution?.name}} · {{item?.exam_date}}</span></div><el-button @click="$router.back()">返回</el-button></section><el-alert title="这里只展示机构确认的标准化指标，不提供编辑、删除或原文件访问。" type="info" show-icon :closable="false"/><el-card shadow="never" v-loading="loading"><el-descriptions v-if="item" :column="2" border><el-descriptions-item v-if="item.subject_name_snapshot" label="受检者姓名快照">{{item.subject_name_snapshot}}</el-descriptions-item><el-descriptions-item label="体检日期">{{item.exam_date}}</el-descriptions-item><el-descriptions-item label="机构">{{item.institution?.name}} · {{item.institution?.branch_name}}</el-descriptions-item><el-descriptions-item label="套餐">{{item.package?.name||'未选择'}}</el-descriptions-item></el-descriptions><el-table :data="item?.indicators||[]" style="margin-top:18px"><el-table-column label="指标"><template #default="s">{{s.row.indicator?.name}}（{{s.row.indicator?.code}}）</template></el-table-column><el-table-column prop="value" label="结果"/><el-table-column label="单位"><template #default="s">{{s.row.indicator?.unit||'-'}}</template></el-table-column><el-table-column label="状态"><template #default="s"><el-tag :type="s.row.is_abnormal?'danger':'success'">{{s.row.is_abnormal?'异常':'正常'}}</el-tag></template></el-table-column></el-table></el-card></div></template><script setup>import{onMounted,ref}from"vue";import{useRoute}from"vue-router";import{fetchExamReport}from"../api/examReports";const route=useRoute(),loading=ref(false),item=ref(null),owner=ref(null);onMounted(async()=>{loading.value=true;try{const{data}=await fetchExamReport(route.params.id);item.value=data.item;owner.value=data.owner}finally{loading.value=false}});</script>
